// ============ STORAGE HELPERS ============
const Storage = {
  async get(key) {
    try { const r = await window.storage.get(key); return r ? JSON.parse(r.value) : null; }
    catch { return null; }
  },
  async set(key, val) {
    try { await window.storage.set(key, JSON.stringify(val)); return true; }
    catch { return false; }
  },
  async list(prefix) {
    try { const r = await window.storage.list(prefix); return r?.keys || []; }
    catch { return []; }
  },
  async delete(key) {
    try { await window.storage.delete(key); return true; }
    catch { return false; }
  }
};

// ============ APP PRINCIPALE ============
export default function App() {
  const [view, setView] = useState("dashboard");
  const [selectedDiag, setSelectedDiag] = useState(null);
  const [selectedSite, setSelectedSite] = useState(null);
  const [diagnostics, setDiagnostics] = useState([]);
  const [sites, setSites] = useState([]);
  const [showNewDiag, setShowNewDiag] = useState(false);
  const [defaultSiteId, setDefaultSiteId] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    (async () => {
      const diagKeys = await Storage.list("diag:");
      const diags = [];
      for (const k of diagKeys) {
        const d = await Storage.get(k);
        if (d) diags.push(d);
      }
      diags.sort((a, b) => b.createdAt - a.createdAt);
      setDiagnostics(diags);

      const siteKeys = await Storage.list("site:");
      const sts = [];
      for (const k of siteKeys) {
        const s = await Storage.get(k);
        if (s) sts.push(s);
      }
      if (sts.length === 0) {
        const demoSite = {
          id: "site_demo",
          nom: "Site démo - Parc thématique",
          client: "Démo",
          createdAt: Date.now()
        };
        await Storage.set("site:" + demoSite.id, demoSite);
        sts.push(demoSite);
      }
      setSites(sts);
      setLoading(false);
    })();
  }, []);

  const refreshDiagnostics = async () => {
    const diagKeys = await Storage.list("diag:");
    const diags = [];
    for (const k of diagKeys) {
      const d = await Storage.get(k);
      if (d) diags.push(d);
    }
    diags.sort((a, b) => b.createdAt - a.createdAt);
    setDiagnostics(diags);
  };

  const refreshSites = async () => {
    const siteKeys = await Storage.list("site:");
    const sts = [];
    for (const k of siteKeys) {
      const s = await Storage.get(k);
      if (s) sts.push(s);
    }
    setSites(sts);
  };

  const deleteSite = async (siteId) => {
    const linkedDiags = diagnostics.filter(d => d.siteId === siteId);
    const msg = linkedDiags.length > 0
      ? `Supprimer ce site et ses ${linkedDiags.length} diagnostic${linkedDiags.length > 1 ? "s" : ""} ? Cette action est irréversible.`
      : "Supprimer ce site ?";
    if (!window.confirm(msg)) return;
    for (const d of linkedDiags) await Storage.delete("diag:" + d.id);
    await Storage.delete("site:" + siteId);
    await refreshSites();
    await refreshDiagnostics();
    setSelectedSite(null);
    setView("sites");
  };

  const deleteDiagnostic = async (diagId) => {
    if (!window.confirm("Supprimer ce diagnostic ? Cette action est irréversible.")) return;
    await Storage.delete("diag:" + diagId);
    await refreshDiagnostics();
    setSelectedDiag(null);
    setView("diagnostics");
  };

  if (loading) {
    return (
      <div style={{
        minHeight: "100vh", background: COLORS.bg,
        display: "flex", alignItems: "center", justifyContent: "center",
        fontFamily: "system-ui, sans-serif"
      }}>
        <div style={{ color: COLORS.navy }}>Chargement...</div>
      </div>
    );
  }

  return (
    <div style={{
      minHeight: "100vh",
      background: COLORS.bg,
      fontFamily: "system-ui, -apple-system, sans-serif",
      color: COLORS.text,
      paddingBottom: "80px",
      maxWidth: "480px",
      margin: "0 auto",
      position: "relative"
    }}>
      <Header view={view} onBack={() => {
        if (selectedDiag) { setSelectedDiag(null); setView("diagnostics"); }
        else if (selectedSite) { setSelectedSite(null); setView("sites"); }
      }} canGoBack={!!selectedDiag || !!selectedSite} />

      <div style={{ padding: "16px" }}>
        {view === "dashboard" && !selectedDiag && (
          <Dashboard
            diagnostics={diagnostics}
            sites={sites}
            onNewDiag={() => { setDefaultSiteId(null); setShowNewDiag(true); }}
            onSelectDiag={(d) => { setSelectedDiag(d); setView("diag-detail"); }}
            setView={setView}
          />
        )}

        {view === "diagnostics" && !selectedDiag && (
          <DiagnosticsList
            diagnostics={diagnostics}
            sites={sites}
            onSelectDiag={(d) => { setSelectedDiag(d); setView("diag-detail"); }}
            onNewDiag={() => { setDefaultSiteId(null); setShowNewDiag(true); }}
          />
        )}

        {view === "diag-detail" && selectedDiag && (
          <DiagnosticDetail
            diag={selectedDiag}
            site={sites.find(s => s.id === selectedDiag.siteId)}
            onDelete={() => deleteDiagnostic(selectedDiag.id)}
          />
        )}

        {view === "sites" && !selectedSite && (
          <SitesList
            sites={sites}
            diagnostics={diagnostics}
            onSelectSite={(s) => { setSelectedSite(s); setView("site-detail"); }}
            onCreate={async (newSite) => {
              await Storage.set("site:" + newSite.id, newSite);
              await refreshSites();
            }}
          />
        )}

        {view === "site-detail" && selectedSite && (
          <SiteDetail
            site={selectedSite}
            diagnostics={diagnostics.filter(d => d.siteId === selectedSite.id)}
            onSelectDiag={(d) => { setSelectedDiag(d); setView("diag-detail"); }}
            onNewDiag={() => { setDefaultSiteId(selectedSite.id); setShowNewDiag(true); }}
            onDelete={() => deleteSite(selectedSite.id)}
          />
        )}

        {view === "settings" && (
          <SettingsView
            diagnostics={diagnostics}
            sites={sites}
            onClearAll={async () => {
              if (!window.confirm("Tout supprimer (diagnostics + sites) ? Cette action est irréversible.")) return;
              // Supprimer toutes les clés diag: et site: en listant directement le storage
              const allDiagKeys = await Storage.list("diag:");
              const allSiteKeys = await Storage.list("site:");
              for (const k of allDiagKeys) await Storage.delete(k);
              for (const k of allSiteKeys) await Storage.delete(k);
              // Recréer le site démo pour ne pas avoir une app vide
              const demoSite = {
                id: "site_demo",
                nom: "Site démo - Parc thématique",
                client: "Démo",
                createdAt: Date.now()
              };
              await Storage.set("site:" + demoSite.id, demoSite);
              setDiagnostics([]);
              setSites([demoSite]);
              window.alert("Toutes les données ont été effacées.");
            }}
          />
        )}
      </div>

      <BottomNav view={view} setView={(v) => { setSelectedDiag(null); setSelectedSite(null); setView(v); }} />

      {showNewDiag && (
        <NewDiagnosticModal
          sites={sites}
          defaultSiteId={defaultSiteId}
          onClose={() => setShowNewDiag(false)}
          onSave={async (d) => {
            await Storage.set("diag:" + d.id, d);
            await refreshDiagnostics();
            setShowNewDiag(false);
          }}
        />
      )}
    </div>
  );
}

