// ============ SITES ============
function SitesList({ sites, diagnostics, onSelectSite, onCreate }) {
  const [showNew, setShowNew] = useState(false);
  const [nom, setNom] = useState("");
  const [client, setClient] = useState("");

  const handleCreate = async () => {
    if (!nom.trim()) return;
    const newSite = {
      id: "s" + Date.now(), nom: nom.trim(), client: client.trim(),
      createdAt: Date.now()
    };
    await onCreate(newSite);
    setShowNew(false); setNom(""); setClient("");
  };

  return (
    <div>
      <button onClick={() => setShowNew(!showNew)}
        style={{
          width: "100%", background: "white", border: `1px dashed ${COLORS.navy}`,
          color: COLORS.navy, borderRadius: "10px", padding: "12px",
          cursor: "pointer", marginBottom: "12px", fontSize: "13px",
          fontWeight: 500, display: "flex", alignItems: "center", justifyContent: "center", gap: "8px"
        }}>
        <Plus size={16} />
        {showNew ? "Annuler" : "Nouveau site"}
      </button>

      {showNew && (
        <div style={{
          background: "white", borderRadius: "10px", padding: "14px",
          marginBottom: "12px", border: `1px solid ${COLORS.border}`
        }}>
          <input type="text" placeholder="Nom du site / parc / ouvrage" value={nom}
            onChange={(e) => setNom(e.target.value)}
            style={{ ...inputStyle, marginBottom: "8px" }} />
          <input type="text" placeholder="Client" value={client}
            onChange={(e) => setClient(e.target.value)}
            style={{ ...inputStyle, marginBottom: "10px" }} />
          <button onClick={handleCreate} disabled={!nom.trim()}
            style={{
              width: "100%", background: nom.trim() ? COLORS.navy : COLORS.border,
              color: "white", border: "none", borderRadius: "8px", padding: "10px",
              fontSize: "13px", fontWeight: 500,
              cursor: nom.trim() ? "pointer" : "not-allowed"
            }}>
            Créer
          </button>
        </div>
      )}

      {sites.length === 0 ? (
        <EmptyState text="Aucun site enregistré" />
      ) : (
        sites.map(s => {
          const count = diagnostics.filter(d => d.siteId === s.id).length;
          const n3 = diagnostics.filter(d => d.siteId === s.id && d.criticite === "n3").length;
          return (
            <button key={s.id} onClick={() => onSelectSite(s)}
              style={{
                width: "100%", background: "white", border: `1px solid ${COLORS.border}`,
                borderRadius: "10px", padding: "14px", marginBottom: "10px",
                display: "flex", alignItems: "center", cursor: "pointer", textAlign: "left", gap: "12px"
              }}>
              <div style={{
                width: "40px", height: "40px", borderRadius: "8px",
                background: COLORS.navy, color: COLORS.gold,
                display: "flex", alignItems: "center", justifyContent: "center", flexShrink: 0
              }}>
                <Building2 size={20} />
              </div>
              <div style={{ flex: 1, minWidth: 0 }}>
                <div style={{
                  fontSize: "14px", fontWeight: 500, marginBottom: "2px",
                  overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap"
                }}>{s.nom}</div>
                <div style={{ fontSize: "11px", color: COLORS.textMuted }}>
                  {s.client || "—"} · {count} observation{count !== 1 ? "s" : ""}
                  {n3 > 0 && (
                    <span style={{ color: COLORS.red, fontWeight: 600 }}> · {n3} N3</span>
                  )}
                </div>
              </div>
              <ChevronRight size={18} color={COLORS.textMuted} />
            </button>
          );
        })
      )}
    </div>
  );
}

function SiteDetail({ site, diagnostics, onSelectDiag, onNewDiag, onDelete }) {
  const stats = {
    total: diagnostics.length,
    n3: diagnostics.filter(d => d.criticite === "n3").length,
    n2: diagnostics.filter(d => d.criticite === "n2").length,
    n1: diagnostics.filter(d => d.criticite === "n1").length,
  };
  return (
    <div>
      <div style={{
        background: COLORS.navy, color: "white", padding: "16px",
        borderRadius: "12px", marginBottom: "12px",
        display: "flex", justifyContent: "space-between", alignItems: "flex-start", gap: "10px"
      }}>
        <div style={{ flex: 1, minWidth: 0 }}>
          <div style={{ fontSize: "10px", color: COLORS.gold, letterSpacing: "1.5px", fontWeight: 600 }}>
            SITE
          </div>
          <div style={{ fontSize: "17px", fontWeight: 500, marginTop: "2px" }}>{site.nom}</div>
          <div style={{ fontSize: "12px", opacity: 0.85, marginTop: "4px" }}>
            Client : {site.client || "—"}
          </div>
        </div>
        <button onClick={onDelete}
          style={{
            background: "rgba(255,255,255,0.1)", border: "none",
            color: "white", borderRadius: "8px", padding: "8px",
            cursor: "pointer", flexShrink: 0
          }}>
          <Trash2 size={16} />
        </button>
      </div>

      <button onClick={onNewDiag}
        style={{
          width: "100%", background: COLORS.gold, color: COLORS.navy,
          border: "none", borderRadius: "10px", padding: "12px",
          cursor: "pointer", marginBottom: "16px", fontSize: "13px",
          fontWeight: 600, display: "flex", alignItems: "center",
          justifyContent: "center", gap: "8px"
        }}>
        <Plus size={16} />
        Nouvelle observation sur ce site
      </button>

      <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: "10px", marginBottom: "20px" }}>
        <StatCard label="Total" value={stats.total} color={COLORS.navy} />
        <StatCard label="N3 immédiat" value={stats.n3} color={COLORS.red} />
        <StatCard label="N2 planifié" value={stats.n2} color={COLORS.amber} />
        <StatCard label="N1 surveillance" value={stats.n1} color={COLORS.green} />
      </div>

      <h3 style={{ fontSize: "14px", fontWeight: 600, color: COLORS.navy, marginBottom: "12px" }}>
        Observations ({diagnostics.length})
      </h3>
      {diagnostics.length === 0 ? (
        <EmptyState text="Aucune observation sur ce site" />
      ) : (
        diagnostics.map(d => (
          <DiagCard key={d.id} diag={d} site={site} onClick={() => onSelectDiag(d)} />
        ))
      )}
    </div>
  );
}

